insert into public.share_card_bank (id, tier, body, attribution, source_note, theme, extra_tags, moment, gloss) values
  ('QB-001', 'classic_public_domain', 'Waste no more time arguing what a good man should be. Be one.', 'Marcus Aurelius', 'Meditations, Bk 10.16, tr. George Long (1862) — PD ✓', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('QB-002', 'classic_public_domain', 'Confine thyself to the present.', 'Marcus Aurelius', 'Meditations Bk 7.29 (not 8.36), tr. George Long — verbatim (''thyself'', not ''yourself'') — PD ✓ (re-audited 13 Jul)', 'attention & presence', ARRAY['practice: stillness']::text[], 'any', NULL),
  ('QB-003', 'classic_public_domain', 'Nothing happens to any man which he is not formed by nature to bear.', 'Marcus Aurelius', 'Meditations Bk 5.18, tr. George Long — verbatim — PD ✓ (re-audited 13 Jul)', 'endurance & the long walk', '{}'::text[], 'hard day', NULL),
  ('QB-004', 'classic_public_domain', 'We are made for co-operation, like feet, like hands, like eyelids.', 'Marcus Aurelius', 'Meditations Bk 2.1, tr. George Long — trimmed from ''For we are made for co-operation, like feet, like hands, like eyelids, like the rows of the upper and lower teeth.'' — PD ✓ (re-audited 13 Jul)', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-005', 'classic_public_domain', 'Begin at once to live, and count each separate day as a separate life.', 'Seneca', 'Letters to Lucilius, Ep. 101, tr. Richard Gummere (Loeb, 1917-25) — PD ✓', 'returning & beginning again', '{}'::text[], 'early days', NULL),
  ('QB-006', 'classic_public_domain', 'We suffer more often in imagination than in reality.', 'Seneca', 'Letters to Lucilius, Ep. 13, tr. Richard Gummere (Loeb, 1917-25) — PD ✓', 'rest & gentleness', '{}'::text[], 'hard day', NULL),
  ('QB-007', 'classic_public_domain', 'Men are disturbed not by the things which happen, but by the opinions about the things.', 'Epictetus', 'Enchiridion, 1, tr. Elizabeth Carter (1758) — PD ✓', 'attention & presence', '{}'::text[], 'hard day', NULL),
  ('QB-008', 'classic_public_domain', 'First say to yourself what you would be; and then do what you have to do.', 'Epictetus', 'Discourses, tr. Elizabeth Carter (1758) — PD ✓', 'craft & practice', '{}'::text[], 'early days', NULL),
  ('QB-009', 'classic_public_domain', 'Never say concerning anything, ''I have lost it,'' but say ''I have restored it.''', 'Epictetus', 'Enchiridion, 11, tr. Elizabeth Carter (1758) — PD ✓', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('QB-010', 'classic_public_domain', 'My trade and my art is to live.', 'Montaigne', 'Essays, Bk 2 ch.6, tr. Charles Cotton (1685-1700)/Hazlitt rev. (1877) — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-011', 'classic_public_domain', 'That which is not good for the swarm is not good for the bee.', 'Marcus Aurelius', 'Meditations, Bk 6.54, tr. George Long (1862) — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', 'What''s bad for the group is bad for the individual too, we''re not separate from each other.'),
  ('QB-012', 'classic_public_domain', 'As is a tale, so is life: not how long it is, but how good it is, is what matters.', 'Seneca', 'Letters to Lucilius, Ep. 77, tr. Richard Gummere (Loeb, 1917-25) — PD ✓', 'the cosmic view', '{}'::text[], 'long arc', NULL),
  ('QB-013', 'classic_public_domain', 'The unexamined life is not worth living.', 'Socrates (as reported by Plato)', 'Apology 38a, tr. Benjamin Jowett (1871) — PD ✓', 'attention & presence', ARRAY['seasoning']::text[], 'long arc', NULL),
  ('QB-014', 'classic_public_domain', 'The soul becomes dyed with the color of its thoughts.', 'Marcus Aurelius', 'Meditations, Bk 5.16, tr. George Long (1862) — PD ✓', 'attention & presence', '{}'::text[], 'any', NULL),
  ('QB-015', 'classic_public_domain', 'A journey of a thousand miles begins with a single step.', 'Laozi', 'Tao Te Ching, ch.64, tr. James Legge (1891) — PD ✓', 'endurance & the long walk', '{}'::text[], 'early days', NULL),
  ('QB-016', 'classic_public_domain', 'Let it be still, and it will gradually become clear.', 'Laozi', 'Tao Teh King ch.15, tr. James Legge (1891), Gutenberg #216 — trimmed to the self-contained second sentence of the muddy-water passage — PD ✓ (re-audited 13 Jul)', 'rest & gentleness', ARRAY['practice: stillness']::text[], 'hard day', NULL),
  ('QB-017', 'classic_public_domain', 'When you see a worthy person, endeavor to emulate him; when you see an unworthy person, examine your inner self.', 'Confucius', 'Analects 4.17, tr. James Legge (1893) — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-018', 'classic_public_domain', 'It is only when the cold season comes that we know the pine and the cypress to be evergreens.', 'Confucius', 'Analects 9.28, tr. James Legge (1893) — PD ✓', 'endurance & the long walk', '{}'::text[], 'hard day', NULL),
  ('QB-019', 'classic_public_domain', 'Our greatest glory is not in never falling, but in rising every time we fall.', 'Oliver Goldsmith', 'The Citizen of the World, Letter VII (1762) — PD ✓', 'returning & beginning again', ARRAY['pass (as writing)']::text[], 'rekindle', NULL),
  ('QB-020', 'classic_public_domain', 'Once, Zhuangzi dreamed he was a butterfly, and did not know if he was a man who had dreamed he was a butterfly, or a butterfly now dreaming he was a man.', 'Zhuangzi', 'Zhuangzi, ch.2 (''Discussion on Making All Things Equal''), tr. James Legge (1891) / Herbert Giles (1889) — PD ✓', 'the cosmic view', '{}'::text[], 'long arc', 'A reminder that what feels real and what feels like a dream aren''t as easy to tell apart as we assume.'),
  ('QB-021', 'classic_public_domain', 'He will win who knows when to fight and when not to fight.', 'Sun Tzu', 'The Art of War, ch.3, tr. Lionel Giles (1910) — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-022', 'classic_public_domain', 'He will win who, prepared himself, waits to take the enemy unprepared.', 'Sun Tzu', 'The Art of War, ch.3, tr. Lionel Giles (1910) — PD ✓', 'endurance & the long walk', '{}'::text[], 'any', NULL),
  ('QB-023', 'classic_public_domain', 'Virtue is not left to stand alone. He who practices it will have neighbors.', 'Confucius', 'Analects 4.25, tr. James Legge (1893) — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-024', 'classic_public_domain', 'He who knows other men is discerning; he who knows himself is intelligent.', 'Laozi', 'Tao Te Ching, ch.33, tr. James Legge (1891) — PD ✓', 'attention & presence', '{}'::text[], 'any', NULL),
  ('QB-025', 'classic_public_domain', 'Let your plans be dark and impenetrable as night, and when you move, fall like a thunderbolt.', 'Sun Tzu', 'The Art of War, ch.7, tr. Lionel Giles (1910) — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-026', 'classic_public_domain', 'The most beautiful experience we can have is the mysterious. It is the source of all true art and science.', 'Albert Einstein', '"Living Philosophies," Simon & Schuster, 1931, p.6 — Authentic ✓ (short-quote exception)', 'attention & presence', '{}'::text[], 'any', NULL),
  ('QB-027', 'classic_public_domain', 'The first principle is that you must not fool yourself — and you are the easiest person to fool.', 'Richard Feynman', '1974 Caltech commencement address (''Cargo Cult Science'') — Authentic ✓ (short-quote exception)', 'attention & presence', '{}'::text[], 'any', NULL),
  ('QB-028', 'classic_public_domain', 'Consciousness is never experienced in the plural, only in the singular.', 'Erwin Schrödinger', 'My View of the World / Mind and Matter — Authentic ✓ (short-quote exception)', 'the cosmic view', '{}'::text[], 'long arc', 'You can never fully know what it''s like to be someone else, only what it''s like to be you.'),
  ('QB-029', 'classic_public_domain', 'What we observe is not nature itself, but nature exposed to our method of questioning.', 'Werner Heisenberg', 'Physics and Philosophy (1958) — Authentic ✓ (short-quote exception)', 'attention & presence', '{}'::text[], 'any', 'The way we look for something shapes what we find.'),
  ('QB-030', 'classic_public_domain', 'How wonderful that we have met with a paradox. Now we have some hope of making progress.', 'Niels Bohr', 'as quoted in Ruth Moore, "Niels Bohr: The Man, His Science, and the World They Changed" (1966), p.196 — Authentic ✓ (short-quote exception)', 'attention & presence', '{}'::text[], 'any', 'Running into a contradiction usually means you''re about to learn something.'),
  ('QB-031', 'classic_public_domain', 'Nothing in life is to be feared — it is only to be understood.', 'Marie Curie', 'widely documented, exact primary citation not pinned this pass — Authentic ✓ (short-quote exception)', 'attention & presence', '{}'::text[], 'hard day', NULL),
  ('QB-032', 'classic_public_domain', 'However mean your life is, meet it and live it; do not shun it and call it hard names.', 'Henry David Thoreau', 'Walden (1854) — PD ✓', 'attention & presence', '{}'::text[], 'hard day', NULL),
  ('QB-033', 'classic_public_domain', 'Forever is composed of nows.', 'Emily Dickinson', 'poem #624 (Franklin) / #690 (Johnson) — PD ✓', 'attention & presence', '{}'::text[], 'any', NULL),
  ('QB-034', 'classic_public_domain', 'Half of what I say is meaningless, but I say it so that the other half may reach you.', 'Kahlil Gibran', 'Sand and Foam (1926) — PD ✓', 'attention & presence', ARRAY['practice: writing']::text[], 'any', NULL),
  ('QB-035', 'classic_public_domain', 'I am large, I contain multitudes.', 'Walt Whitman', 'Song of Myself, §51 — PD ✓', 'attention & presence', '{}'::text[], 'long arc', NULL),
  ('QB-036', 'classic_public_domain', 'Yesterday is but today''s memory, and tomorrow is today''s dream.', 'Kahlil Gibran', 'The Prophet, "On Time" (1923) — PD ✓', 'returning & beginning again', '{}'::text[], 'any', NULL),
  ('QB-037', 'classic_public_domain', 'If you shed tears when you miss the sun, you also miss the stars.', 'Rabindranath Tagore', 'Stray Birds (1916, self-translated into English) — PD ✓', 'attention & presence', '{}'::text[], 'hard day', NULL),
  ('QB-038', 'classic_public_domain', 'He who binds to himself a joy does the winged life destroy; he who kisses the joy as it flies lives in eternity''s sunrise.', 'William Blake', 'Eternity (Pickering Manuscript, c.1803) — PD ✓', 'attention & presence', '{}'::text[], 'any', 'Try to hold onto a happy moment too tightly and you kill it - let it pass through you and you get to keep touching something bigger.'),
  ('QB-039', 'classic_public_domain', 'Getting and spending, we lay waste our powers.', 'William Wordsworth', '"The World Is Too Much With Us" (1802/1807) — PD ✓', 'attention & presence', '{}'::text[], 'any', 'We burn through our energy chasing and consuming, and lose touch with what we are actually capable of.'),
  ('QB-040', 'classic_public_domain', 'Nothing, Lucilius, is ours, except time.', 'Seneca', 'Seneca, Letters Ep. 1 (On Saving Time) §3, tr. Richard Gummere (1917, PD) — PD ✓ (re-audited 13 Jul)', 'attention & presence', '{}'::text[], 'any', NULL),
  ('QB-041', 'classic_public_domain', 'Not knowing when the dawn will come / I open every door', 'Emily Dickinson', '''Dawn'', Poems by Emily Dickinson, Third Series, ed. Todd (1896); PG #12241 — first two lines of the quatrain, 1896 wording — PD ✓ (re-audited 13 Jul)', 'attention & presence', '{}'::text[], 'hard day', NULL),
  ('QB-042', 'classic_public_domain', 'No great thing is created suddenly.', 'Epictetus', 'Discourses, tr. George Long (1877) or Elizabeth Carter (1758) — PD ✓', 'craft & practice', '{}'::text[], 'early days', NULL),
  ('QB-043', 'classic_public_domain', 'I dwell in possibility.', 'Emily Dickinson', 'poem #466 (Franklin) / #657 (Johnson) — PD ✓', 'craft & practice', ARRAY['practice: writing']::text[], 'any', NULL),
  ('QB-044', 'classic_public_domain', 'Work is love made visible.', 'Kahlil Gibran', 'The Prophet, "On Work" (1923) — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-045', 'classic_public_domain', 'Trust thyself: every heart vibrates to that iron string.', 'Ralph Waldo Emerson', 'Self-Reliance (1841) — PD ✓', 'craft & practice', '{}'::text[], 'early days', NULL),
  ('QB-046', 'classic_public_domain', 'He who aims to be a man of complete virtue in his food does not seek to gratify his appetite, nor in his dwelling place does he seek the appliances of ease; he is earnest in what he is doing, and careful in his speech.', 'Confucius', 'Analects 1.14, tr. James Legge (1893) — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-047', 'classic_public_domain', 'They who know the truth are not equal to those who love it, and they who love it are not equal to those who delight in it.', 'Confucius', 'Confucian Analects VI.18 (Legge''s numbering; 6.20 in some modern editions), tr. James Legge, Gutenberg #4094 — PD ✓ (re-audited 13 Jul)', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('QB-048', 'classic_public_domain', 'I learned this, at least, by my experiment: that if one advances confidently in the direction of his dreams, and endeavors to live the life which he has imagined, he will meet with a success unexpected in common hours.', 'Henry David Thoreau', 'Walden, "Conclusion" (1854) — PD ✓', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('QB-049', 'classic_public_domain', 'Thy right is to work only, but never to its fruits; let the fruit of action be not thy motive, nor let thy attachment be to inaction.', 'The Bhagavad Gita', 'The Song Celestial, tr. Sir Edwin Arnold (1885), ch.2 v.47 — PD ✓', 'craft & practice', '{}'::text[], 'any', 'Do the work for its own sake, don''t get hung up on the outcome.'),
  ('QB-050', 'classic_public_domain', 'If he is indeed wise he does not bid you enter the house of his wisdom, but rather leads you to the threshold of your own mind.', 'Kahlil Gibran', 'The Prophet, "On Teaching" (1923) — PD ✓', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('QB-051', 'classic_public_domain', 'All urge is blind save when there is knowledge, and all knowledge is vain save when there is work, and all work is empty save when there is love.', 'Kahlil Gibran', 'The Prophet, "On Work" (1923) — PD ✓', 'craft & practice', '{}'::text[], 'any', 'Instinct needs knowledge, knowledge needs action, and action needs love, or none of it means much.'),
  ('QB-052', 'classic_public_domain', 'Simplicity, simplicity, simplicity!', 'Henry David Thoreau', 'Walden, "Where I Lived, and What I Lived For" (1854) — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-053', 'classic_public_domain', 'Of things some are in our power, and others are not.', 'Epictetus', 'Enchiridion, ch.1, tr. George Long — PD ✓', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-054', 'classic_public_domain', 'No man is free who is not master of himself.', 'attributed to Epictetus', 'Fragments attributed to Epictetus (via Stobaeus), Fragment XV, tr. Hastings Crossley, The Golden Sayings of Epictetus (PD) — PD ✓ (re-audited 13 Jul)', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-055', 'classic_public_domain', 'Everyone thinks of changing the world, but nobody thinks of changing himself.', 'Leo Tolstoy', '"Three Methods of Reform," in Pamphlets Translated from the Russian (1900) — PD ✓', 'returning & beginning again', '{}'::text[], 'any', NULL),
  ('QB-056', 'classic_public_domain', 'The secret of man''s being is not only to live but to have something to live for.', 'Fyodor Dostoevsky', 'The Brothers Karamazov, tr. Constance Garnett (1912) — PD ✓', 'the cosmic view', '{}'::text[], 'long arc', NULL),
  ('QB-057', 'classic_public_domain', 'These virtues are formed in man by his doing the actions.', 'Aristotle', 'Nicomachean Ethics, Book II, tr. W. D. Ross (1908) — PD ✓', 'craft & practice', '{}'::text[], 'any', 'You become virtuous by doing virtuous things, not the other way round - the habit comes first, the character follows.'),
  ('QB-058', 'classic_public_domain', 'The beginning is the most important part of any work, especially in the case of a young and tender thing, for that is the time at which the character is being formed.', 'Plato', 'The Republic, Book II, tr. Benjamin Jowett — PD ✓', 'returning & beginning again', '{}'::text[], 'any', NULL),
  ('QB-059', 'classic_public_domain', 'Every one may carry on his own experiments according to his own inclination and capacity.', 'Mahatma Gandhi', 'An Autobiography (The Story of My Experiments with Truth), Introduction, tr. Mahadev Desai, Vol. I (1927) — trimmed from the Introduction sentence — PD ✓', 'craft & practice', '{}'::text[], 'early days', 'Gandhi framed his own life as a series of small experiments — try it your own way, at your own scale.'),
  ('QB-060', 'classic_public_domain', 'Be the change you want to see in the world.', 'Unknown', 'APOCRYPHAL as Gandhi (he never wrote it; the phrasing traces to Arleen Lorrance, 1970s). Rendered with NO card author line per the apocryphal-unattributed rule (Cat 13 Jul). The genuine Gandhi analog (''We but mirror the world...'') survives only in a copyrighted CWMG translation, so it can''t be used verbatim. — Apocryphal — no author line (Cat-approved)', 'craft & practice', '{}'::text[], 'any', NULL),
  ('QB-061', 'classic_public_domain', 'Do one thing every day that scares you.', 'Unknown', 'APOCRYPHAL as Eleanor Roosevelt (no primary source; a paraphrase of her genuine ''look fear in the face'' passage). Unattributed by design (Cat 13 Jul). — Apocryphal — no author line (Cat-approved)', 'craft & practice', '{}'::text[], 'early days', NULL),
  ('QB-062', 'classic_public_domain', 'Live as if you were to die tomorrow. Learn as if you were to live forever.', 'Unknown', 'APOCRYPHAL as Gandhi (no primary source; the sentiment predates him). Unattributed by design (Cat 13 Jul). — Apocryphal — no author line (Cat-approved)', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('QB-063', 'classic_public_domain', 'New beginnings are often disguised as painful endings.', 'Unknown', 'no traceable primary source (long misattributed to Lao Tzu; not in the Tao Te Ching) — Untraceable — Cat-approved', 'returning & beginning again', ARRAY['pass (as writing)']::text[], 'rekindle', NULL),
  ('QB-064', 'classic_public_domain', 'First the fall, and then the recovery from the fall, and both are the mercy of God.', 'Julian of Norwich', 'Revelations of Divine Love, tr. Grace Warrack (1901) — PD ✓', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('QB-065', 'classic_public_domain', 'We always may be what we might have been.', 'Adelaide Anne Procter', 'poem, mid-19th century — PD ✓', 'returning & beginning again', '{}'::text[], 'any', NULL),
  ('QB-066', 'classic_public_domain', 'If a man keeps cherishing his old knowledge, so as continually to be acquiring new, he may be a teacher of others.', 'Confucius', 'Confucian Analects II.11, tr. James Legge, Gutenberg #4094 — PD ✓ (re-audited 13 Jul)', 'craft & practice', '{}'::text[], 'long arc', 'Keep revisiting what you already know while staying open to new things - that combination is what makes someone worth learning from.'),
  ('QB-067', 'classic_public_domain', 'Better by far you should forget and smile than that you should remember and be sad.', 'Christina Rossetti', '"Remember" (1862) — PD ✓', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('QB-068', 'classic_public_domain', 'It is not that we have a short time to live, but that we waste a lot of it.', 'Seneca', 'De Brevitate Vitae (''On the Shortness of Life''), tr. Aubrey Stewart (1900) — PD ✓', 'rest & gentleness', '{}'::text[], 'any', NULL),
  ('QB-069', 'classic_public_domain', 'All shall be well, and all shall be well, and all manner of thing shall be well.', 'Julian of Norwich', 'Revelations of Divine Love, tr. Grace Warrack (1901) — PD ✓', 'rest & gentleness', '{}'::text[], 'hard day', NULL),
  ('QB-070', 'classic_public_domain', 'That it will never come again is what makes life so sweet.', 'Emily Dickinson', 'poem #1741 (Johnson) — PD ✓', 'rest & gentleness', '{}'::text[], 'any', NULL),
  ('QB-071', 'classic_public_domain', 'Time is but the stream I go a-fishing in.', 'Henry David Thoreau', 'Walden (1854) — PD ✓', 'rest & gentleness', '{}'::text[], 'any', NULL),
  ('QB-072', 'classic_public_domain', 'Doubt is a pain too lonely to know that faith is his twin brother.', 'Kahlil Gibran', 'Sand and Foam (1926) — PD ✓', 'rest & gentleness', ARRAY['seasoning']::text[], 'hard day', NULL),
  ('QB-073', 'classic_public_domain', 'Seek not that the things which happen should happen as you wish; but wish the things which happen to be as they are, and you will have a tranquil flow of life.', 'Epictetus', 'Enchiridion, ch.8, tr. George Long — PD ✓', 'returning & beginning again', '{}'::text[], 'hard day', NULL),
  ('QB-074', 'classic_public_domain', 'The deeper that sorrow carves into your being, the more joy you can contain.', 'Kahlil Gibran', 'The Prophet, "On Joy and Sorrow" (1923) — PD ✓', 'rest & gentleness', '{}'::text[], 'hard day', NULL),
  ('QB-075', 'classic_public_domain', 'Your joy is your sorrow unmasked.', 'Kahlil Gibran', 'The Prophet, "On Joy and Sorrow" (1923) — PD ✓', 'rest & gentleness', '{}'::text[], 'hard day', NULL),
  ('QB-076', 'classic_public_domain', 'He who is satisfied with his lot is rich.', 'Laozi', 'Tao Teh King ch.33 (not 44), tr. James Legge (1891), Gutenberg #216 — trimmed to the self-contained first clause — PD ✓ (re-audited 13 Jul)', 'rest & gentleness', '{}'::text[], 'any', NULL),
  ('QB-077', 'classic_public_domain', 'My friends are my estate.', 'Emily Dickinson', 'letter to Samuel Bowles (1858) / widely documented — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-078', 'classic_public_domain', 'Regard him as loyal, and you will make him loyal.', 'Seneca', 'Letters to Lucilius, Ep. 3, tr. Richard Gummere (Loeb, 1917-25) — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-079', 'classic_public_domain', 'Friendship is a single soul dwelling in two bodies.', 'Aristotle (as reported by Diogenes Laertius)', 'Diogenes Laertius, Lives of the Eminent Philosophers, Bk V.20, tr. R.D. Hicks (Loeb, 1925) — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-080', 'classic_public_domain', 'You give but little when you give of your possessions. It is when you give of yourself that you truly give.', 'Kahlil Gibran', 'The Prophet, "On Giving" (1923) — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-081', 'classic_public_domain', 'Camerado, I give you my hand! I give you my love more precious than money, I give you myself before preaching or law.', 'Walt Whitman', 'Song of the Open Road, §5 — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-082', 'classic_public_domain', 'Withdraw into yourself, as far as you can. Associate with those who will make a better man of you.', 'Seneca', 'Seneca, Letters Ep. 7 (On Crowds) §8, tr. Richard Gummere (1917, PD) — PD ✓ (re-audited 13 Jul)', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-083', 'classic_public_domain', 'And in the sweetness of friendship let there be laughter, and sharing of pleasures. For in the dew of little things the heart finds its morning and is refreshed.', 'Kahlil Gibran', 'The Prophet, "On Friendship" (1923) — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-084', 'classic_public_domain', 'What you do not want done to yourself, do not do to others.', 'Confucius', 'Confucian Analects XV.23 (Legge''s numbering), tr. James Legge — PD ✓ (re-audited 13 Jul)', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-085', 'classic_public_domain', 'Adapt thyself to the things with which thy lot has been cast: and the men among whom thou hast received thy portion, love them, but do it truly, sincerely.', 'Marcus Aurelius', 'Meditations Bk 6.39, tr. George Long — verbatim (thou-form is Long''s) — PD ✓ (re-audited 13 Jul)', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-086', 'classic_public_domain', 'It seems to men that they live by care for themselves, but in truth it is love alone by which they live.', 'Leo Tolstoy', '"What Men Live By" (1885), tr. Aylmer Maude — PD ✓', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('QB-087', 'classic_public_domain', 'Be kind, for everyone you meet is fighting a hard battle.', 'Unknown', 'Widely circulated proverb, commonly (but not verifiably) linked to Ian Maclaren / Philo of Alexandria - no confirmed original source — Untraceable — Cat-approved', 'friendship & carrying each other', '{}'::text[], 'any', NULL),
  ('QB-088', 'classic_public_domain', 'Piglet noticed that even though he had a Very Small Heart, it could hold a rather large amount of Gratitude.', 'A. A. Milne', 'Winnie-the-Pooh (1926) — US public domain since 1 Jan 2022 (95 years after 1926 publi', 'friendship & carrying each other', '{}'::text[], 'any', NULL),
  ('QB-089', 'classic_public_domain', '"Eeyore," he said solemnly, "I, Winnie-the-Pooh, will find your tail for you." "Thank you, Pooh," answered Eeyore. "You are a real friend."', 'A. A. Milne', 'Winnie-the-Pooh (1926), "Eeyore Loses a Tail" — US public domain since 1 Jan 2022', 'friendship & carrying each other', '{}'::text[], 'any', NULL),
  ('QB-090', 'classic_public_domain', 'Look round at the courses of the stars, as if thou wert going along with them; and constantly consider the changes of the elements into one another.', 'Marcus Aurelius', 'Meditations, Bk 7.47, tr. George Long (1862) — PD ✓', 'the cosmic view', '{}'::text[], 'long arc', NULL),
  ('QB-091', 'classic_public_domain', 'I am forever walking upon these shores, between the sand and the foam. The tide will erase my footprints, and the wind will blow away the foam — but the sea and the shore will remain forever.', 'Kahlil Gibran', 'Sand and Foam, opening passage (1926) — PD ✓', 'the cosmic view', '{}'::text[], 'long arc', 'I keep changing day to day, but the world I''m walking through stays.'),
  ('QB-092', 'classic_public_domain', 'I celebrate myself, and sing myself, and what I assume you shall assume, for every atom belonging to me as good belongs to you.', 'Walt Whitman', 'Song of Myself, §1 (1855/1892 ed.) — PD ✓', 'the cosmic view', '{}'::text[], 'any', NULL),
  ('QB-093', 'classic_public_domain', 'Clouds come floating into my life, no longer to carry rain or usher storm, but to add color to my sunset sky.', 'Rabindranath Tagore', 'Stray Birds (1916) — PD ✓', 'returning & beginning again', '{}'::text[], 'long arc', NULL),
  ('QB-094', 'classic_public_domain', 'To see a World in a Grain of Sand and a Heaven in a Wild Flower, hold Infinity in the palm of your hand and Eternity in an hour.', 'William Blake', 'Auguries of Innocence (written c.1803, published 1863) — PD ✓', 'the cosmic view', '{}'::text[], 'any', NULL),
  ('QB-095', 'classic_public_domain', 'The universe is transformation: life is opinion.', 'Marcus Aurelius', 'Meditations, Bk 4.3, tr. George Long (1862) — PD ✓', 'the cosmic view', '{}'::text[], 'any', 'External things can''t touch you, only your judgment about them can, and everything is in flux anyway.'),
  ('QB-096', 'classic_public_domain', 'The years teach much which the days never know.', 'Ralph Waldo Emerson', '''Experience'', Essays: Second Series (1844); PG #2945 — PD ✓ (re-audited 13 Jul)', 'returning & beginning again', '{}'::text[], 'long arc', NULL),
  ('QB-097', 'classic_public_domain', 'Very little indeed is necessary for living a happy life.', 'Marcus Aurelius', 'Meditations Bk 7.67, tr. George Long (1862; PG #15877, verified vs MIT Classics + Standard Ebooks) — trimmed from ''Always bear this in mind; and another thing too, that very little indeed is necessary for living a happy life.'' — PD ✓ (re-audited 13 Jul)', 'the cosmic view', ARRAY['seasoning']::text[], 'long arc', NULL),
  ('QB-098', 'classic_public_domain', 'In wildness is the preservation of the world.', 'Henry David Thoreau', '"Walking" (1862 essay, published posthumously) — PD ✓', 'nature & seasons', '{}'::text[], 'any', NULL),
  ('QB-099', 'classic_public_domain', 'There is no season such delight can bring, as summer, autumn, winter, and the spring.', 'William Browne', 'Britannia''s Pastorals (early 1600s) — PD ✓', 'nature & seasons', ARRAY['seasoning']::text[], 'any', NULL),
  ('QB-100', 'classic_public_domain', 'If winter should say "Spring is in my heart," who would believe winter?', 'Kahlil Gibran', 'Sand and Foam (1926) — PD ✓', 'nature & seasons', '{}'::text[], 'any', NULL),
  ('QB-101', 'classic_public_domain', 'Leave this military hurry and adopt the pace of Nature. Her secret is patience.', 'Ralph Waldo Emerson', '''Education'', Lectures and Biographical Sketches (1883, posthumous, ed. Cabot; verified against the 1891 Houghton Mifflin printing, p.132) — PD ✓ (re-audited 13 Jul)', 'nature & seasons', '{}'::text[], 'any', NULL),
  ('QB-102', 'classic_public_domain', 'It is the tears of the earth that keep her smiles in bloom.', 'Rabindranath Tagore', 'Stray Birds (1916) — PD ✓', 'nature & seasons', '{}'::text[], 'any', NULL),
  ('QB-103', 'classic_public_domain', 'A thing of beauty is a joy for ever: its loveliness increases; it will never pass into nothingness.', 'John Keats', 'Endymion (1818), opening lines — PD ✓', 'attention & presence', '{}'::text[], 'any', NULL),
  ('QB-104', 'classic_public_domain', 'Now I see the secret of the making of the best persons, / It is to grow in the open air and to eat and sleep with the earth.', 'Walt Whitman', '''Song of the Open Road'' §6 (not Song of Myself), Leaves of Grass, 1891-92 ''deathbed'' edition, p.133 — PD ✓ (re-audited 13 Jul)', 'nature & seasons', '{}'::text[], 'any', NULL),
  ('QB-105', 'classic_public_domain', 'It does not matter how slowly you go as long as you do not stop.', 'Unknown', 'no traceable primary source (web-verified: not in the Analects, no real author found) — Untraceable — Cat-approved', 'endurance & the long walk', ARRAY['pass (as writing)']::text[], 'any', NULL),
  ('QB-106', 'classic_public_domain', 'Not till we are lost, in other words, not till we have lost the world, do we begin to find ourselves.', 'Henry David Thoreau', 'Walden (1854) — PD ✓', 'endurance & the long walk', '{}'::text[], 'long arc', NULL),
  ('QB-107', 'classic_public_domain', 'Your pain is the breaking of the shell that encloses your understanding.', 'Kahlil Gibran', 'The Prophet, "On Pain" (1923) — PD ✓', 'endurance & the long walk', '{}'::text[], 'hard day', NULL),
  ('QB-108', 'classic_public_domain', 'Does the road wind uphill all the way? Yes, to the very end.', 'Christina Rossetti', 'Uphill (1861) — PD ✓', 'endurance & the long walk', '{}'::text[], 'hard day', NULL),
  ('QB-109', 'classic_public_domain', 'Sometimes even to live is an act of courage.', 'Seneca', 'Letters to Lucilius, Ep. 78, tr. Richard Gummere (Loeb, 1917-25) — PD ✓', 'endurance & the long walk', '{}'::text[], 'hard day', NULL),
  ('QB-110', 'classic_public_domain', 'Arise, awake, and stop not till the goal is reached.', 'Swami Vivekananda', 'lecture, Calcutta, 1897 (The Complete Works of Swami Vivekananda) — Authentic ✓ (short-quote exception)', 'endurance & the long walk', '{}'::text[], 'any', NULL),
  ('QB-111', 'classic_public_domain', 'You shall be free indeed when your days are not without a care nor your nights without a want and a grief, but rather when these things girdle your life and yet you rise above them naked and unbound.', 'Kahlil Gibran', 'The Prophet, "On Freedom" (1923) — PD ✓', 'endurance & the long walk', '{}'::text[], 'hard day', 'True freedom isn''t the absence of hardship, it''s carrying it without being defined by it.'),
  ('QB-112', 'classic_public_domain', 'Lives of great men all remind us we can make our lives sublime, and, departing, leave behind us footprints on the sands of time.', 'Henry Wadsworth Longfellow', '"A Psalm of Life" (1838) — PD ✓', 'endurance & the long walk', '{}'::text[], 'long arc', NULL),
  ('QB-113', 'classic_public_domain', 'He who fears death will never act as becomes a living man.', 'Seneca', 'Seneca, Of Peace of Mind (De Tranquillitate Animi) ch. XI, tr. Aubrey Stewart (1889, PD; PG #64576) — PD ✓ (re-audited 13 Jul)', 'endurance & the long walk', '{}'::text[], 'hard day', NULL),
  ('QB-114', 'classic_public_domain', 'He said not: thou shalt not be tempested, thou shalt not be travailed, thou shalt not be afflicted; but he said: thou shalt not be overcome.', 'Julian of Norwich', 'Revelations of Divine Love, tr. Grace Warrack (1901) — PD ✓', 'endurance & the long walk', '{}'::text[], 'hard day', 'You''re not promised an easy road, just that hardship won''t be the end of the story.'),
  ('QB-115', 'classic_public_domain', 'I turn my wheel that spins its circle fairly; I delight to make the lowest turn to the top, the highest to the bottom.', 'Boethius', 'The Consolation of Philosophy, Book II, tr. W. V. Cooper (1902) — PD ✓', 'the cosmic view', '{}'::text[], 'hard day', 'Fortune is speaking here, and her whole point is that change is the deal, not a betrayal of it.'),
  ('QB-116', 'classic_public_domain', 'The path of self-purification is hard and steep.', 'Mahatma Gandhi', 'An Autobiography, ''Farewell'', tr. Mahadev Desai, Vol. II (1929) — trimmed from ''But the path...'' — PD ✓', 'endurance & the long walk', '{}'::text[], 'hard day', 'The work of changing yourself is slow and steep — that''s the nature of it, not a sign you''re failing.'),
  ('NF-01', 'fact', 'Two particles, once entangled, stay correlated across any distance — measure one and you already know the other, however far apart they''ve traveled.', NULL, 'Quantum entanglement: linked particles show correlated measurement outcomes regardless of distance. Does NOT allow faster-than-light communication — outcomes are random and no message is sent. — Confirmed via multiple sources incl. Science News, NASA; Einstein''s own "spooky action at a distance" framing, later proven real by Bell test experiments…', 'physics & wonder', '{}'::text[], 'any', NULL),
  ('NF-02', 'fact', 'Underground, a forest is one connected thing. Trees share sugar through fungal threads in the soil — a well-fed tree feeding a struggling one it has never touched above ground.', NULL, 'Mycorrhizal ("wood wide web") networks: fungal threads connect tree root systems, allowing carbon/nutrient transfer from surplus to deficit trees and pest-warning signals between them. — Peer-reviewed research incl. Suzanne Simard''s work, Annals of Botany, Nature journal studies.', 'friendship & carrying each other', '{}'::text[], 'any', NULL),
  ('NF-03', 'fact', 'Geese flying in formation take turns at the front. When the lead bird tires, it falls back, and another rises to break the wind — the whole flock goes farther than any one of them could alone.', NULL, 'Geese (and other birds) flying in V formation save significant energy from the updraft of the bird ahead (estimates range ~12-36% depending on study) and rotate the leading position. — Multiple verified studies incl. J. Exp. Biol. 1987 (Canada geese wing-tip spacing study), 2001 pelican heart-rate monitor study.', 'friendship & carrying each other', '{}'::text[], 'any', NULL),
  ('NF-04', 'fact', 'A redwood''s roots only go a few feet deep — nowhere near enough to hold up a tree that tall alone. What holds it up is that its roots are tangled with its neighbors'' roots.', NULL, 'Coastal redwood root systems are shallow (6-12 ft deep) but spread 60-80 ft wide and interlock with neighboring redwoods, providing mutual stability against wind/flood. — Multiple sources incl. Sempervirens Fund, UC Davis Arboretum materials.', 'friendship & carrying each other', '{}'::text[], 'any', NULL),
  ('NF-05', 'fact', 'No starling leads a murmuration. Each one only tracks the six or seven birds nearest to it — and from that small circle of attention, thousands of birds turn together as if they were one.', NULL, 'Starling murmurations: each bird tracks ~7 nearest neighbors ("scale-free correlation"); coordinated flock movement emerges with no central leader. — Confirmed via 2008 Rome starling study (3D reconstruction) and 2013 Princeton/Italian physicist collaboration, published in PLOS Computational Biology.', 'the cosmic view', '{}'::text[], 'any', NULL),
  ('NF-06', 'fact', 'Some bamboo spends its first years doing nothing you''d notice above ground — building roots in the dark. Then it grows several feet in a matter of weeks.', NULL, 'Certain bamboo species spend early years ("sleep, creep") building an extensive underground rhizome/root system before rapid visible above-ground growth ("leap"). — Multiple horticultural sources; general pattern well-documented for running bamboo species (e.g. Phyllostachys).', 'craft & practice', '{}'::text[], 'any', NULL),
  ('NF-07', 'fact', 'A sea turtle can cross an ocean and still find her way back to the same stretch of beach she hatched on, decades later — she imprinted on it before she ever saw the world.', NULL, 'Natal homing: female sea turtles imprint on the magnetic signature of their hatching beach as hatchlings and use it to navigate back as adults to nest, years/decades later. — Geomagnetic imprinting hypothesis, PNAS 2008 paper; supported by a 19-year loggerhead nesting database study (UNC Lohmann Lab).', 'returning & beginning again', '{}'::text[], 'any', NULL),
  ('NF-08', 'fact', 'Every time you repeat something, the pathway in your brain behind it gets a little stronger and a little faster — practice isn''t just a metaphor for change, it''s the literal mechanism.', NULL, 'Neuroplasticity: repeated activation of the same neural pathway strengthens synaptic connections and increases myelination, speeding up signal transmission - the basis of habit formation and skill-building. — Well-established neuroscience (Hebbian learning, "neurons that fire together wire together"); general mechanism widely confirmed across sources.', 'craft & practice', '{}'::text[], 'any', NULL),
  ('NF-09', 'fact', 'The idea that it takes 21 days to build a habit is a myth. A 2009 University College London study found it takes 66 days on average for a new behavior to feel automatic — and for some people, as long as 254.', NULL, 'Phillippa Lally et al., UCL, European Journal of Social Psychology (2009): tracked 96 people forming a new habit; average time to automaticity was 66 days, range 18-254 days. The "21 days" figure traces to a 1960s… — Lally et al. 2009, EJSP; UCL News coverage.', 'craft & practice', '{}'::text[], 'any', NULL),
  ('NF-10', 'fact', 'In that same study, missing a single day made no measurable difference to how automatic the habit eventually became. One missed day does not erase what you have built.', NULL, 'Same Lally et al. 2009 study: a single missed repetition had no statistically significant effect on the automaticity trajectory (though too many missed days spread out did lower the eventual ceiling). — Lally et al. 2009, EJSP.', 'returning & beginning again', '{}'::text[], 'any', NULL),
  ('NF-11', 'fact', 'The more you repeat something, the less of your brain has to think about it. Neuroscientists have watched the brain activity behind a repeated routine shrink to a single burst at the start and another at the finish — the middle goes quiet, because it has learned to do it without watching.', NULL, '"Chunking": as behavior becomes habitual, the basal ganglia compresses a multi-step sequence into a single neural unit; MIT (Ann Graybiel lab) research found neurons fire strongly at the start/end of a habitual routine… — Graybiel lab, MIT McGovern Institute; widely replicated basal ganglia research.', 'craft & practice', '{}'::text[], 'any', NULL),
  ('NF-12', 'fact', 'The good feeling does not only arrive with the reward. Brain-reward research has found dopamine activity rising in anticipation, before the reward itself arrives - which is part of why showing up can start to feel good before you have even finished.', NULL, 'Wolfram Schultz''s reward prediction error research: dopamine neurons signal in anticipation of an expected reward, not only upon receiving it. — Schultz, W. et al. - foundational dopamine/reward-prediction-error research, J. Neurophysiol. and later reviews.', 'craft & practice', '{}'::text[], 'any', NULL),
  ('NF-13', 'fact', 'Did you know? Emperor penguin fathers walk up to 100km across the ice to reach the breeding colony, then fast for around four months straight, balancing a single egg on their feet the whole time.', NULL, 'Emperor penguins trek roughly 50-120km (some colonies further) from open sea to breeding sites, then males fast through courtship and incubation (about 4 months total) while holding the egg on their feet under a brood… — Australian Antarctic Program; Wikipedia (Emperor penguin); multiple zoology sources cross-checked.', 'endurance & the long walk', '{}'::text[], 'any', NULL),
  ('NF-14', 'fact', 'Did you know? Emperor penguins survive Antarctic winters as cold as minus 60 degrees by huddling together, and they take turns at the freezing outer edge so no single bird carries the cold alone.', NULL, 'Emperor penguins huddle in groups (sometimes thousands strong) to conserve heat in temperatures down to -60C and winds up to 200km/h; individuals rotate from the exposed outer edge toward the warmer centre over time. — Australian Antarctic Program; British Antarctic Survey; Wikipedia (Emperor penguin) - huddling/rotation behaviour is well documented.', 'friendship & carrying each other', '{}'::text[], 'any', NULL),
  ('NF-15', 'fact', 'Did you know? Emperor penguins are the only animal that breeds through the full Antarctic winter, when almost every other creature has left. They start their whole year by walking toward the hardest season, not away from it.', NULL, 'Emperor penguins are unique among penguin species (and among Antarctic animals generally) in beginning their breeding cycle at the start of the Antarctic winter, marching inland to colonies as conditions worsen rather… — Australian Antarctic Program; British Antarctic Survey.', 'returning & beginning again', '{}'::text[], 'any', NULL),
  ('MV-01', 'modern_voice_in_copyright', 'Our deepest fear is not that we are inadequate. Our deepest fear is that we are powerful beyond measure. It is our light, not our darkness, that most frightens us.', 'Marianne Williamson', 'A Return to Love (1992), ch. 7 — IN COPYRIGHT; trimmed from the longer passage (full version leans on ''God'' language + exceeds the card length ceiling). Often misattributed to Mandela''s inaugural — attribute to Williamson.', 'courage & inner light', '{}'::text[], 'hard day', NULL),
  ('MV-02', 'modern_voice_in_copyright', 'After climbing a great hill, one only finds that there are many more hills to climb.', 'Nelson Mandela', 'Long Walk to Freedom (1994), closing pages — IN COPYRIGHT; trimmed from the fuller sentence. Mandela Foundation actively polices use of his words, so treat as attributed short excerpt only.', 'endurance & the long walk', ARRAY['journey ladder']::text[], 'long arc', NULL),
  ('MV-03', 'modern_voice_in_copyright', 'I learned that courage was not the absence of fear, but the triumph over it.', 'Nelson Mandela', 'Long Walk to Freedom (1994) — IN COPYRIGHT; trimmed to the first sentence of the passage. Attributed short excerpt only.', 'courage', '{}'::text[], 'hard day', NULL),
  ('MV-04', 'modern_voice_in_copyright', 'You must do the thing you think you cannot do.', 'Eleanor Roosevelt', 'You Learn by Living (1960), ''Fear — the Great Enemy'' — IN COPYRIGHT; the closing line of the passage. Attributed short excerpt only.', 'courage & doing the thing you fear', '{}'::text[], 'hard day', NULL),
  ('AN-01', 'original_unattributed', 'Showing up small still counts as showing up.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('AN-02', 'original_unattributed', 'You don''t have to feel ready to begin. You just have to begin.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'returning & beginning again', '{}'::text[], 'early days', NULL),
  ('AN-03', 'original_unattributed', 'The day you almost skipped and didn''t is the one that builds you.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'craft & practice', '{}'::text[], 'hard day', NULL),
  ('AN-04', 'original_unattributed', 'Miss a day, and the road back is still open. It always is.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('AN-05', 'original_unattributed', 'Small and steady outlasts big and rare.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('AN-06', 'original_unattributed', 'Be gentle with the version of you that''s still learning.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'rest & gentleness', '{}'::text[], 'hard day', NULL),
  ('AN-07', 'original_unattributed', 'You are not behind. You are one day in, again.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('AN-08', 'original_unattributed', 'Rest is part of the practice, not a break from it.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'rest & gentleness', '{}'::text[], 'any', NULL),
  ('AN-09', 'original_unattributed', 'The habit you keep quietly is stronger than the one you announce.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('AN-10', 'original_unattributed', 'Done imperfectly beats planned perfectly.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'craft & practice', '{}'::text[], 'any', NULL),
  ('AN-11', 'original_unattributed', 'Start before you feel like it. The feeling tends to follow.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'craft & practice', '{}'::text[], 'hard day', NULL),
  ('AN-12', 'original_unattributed', 'Some days the whole win is that you came back.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('AN-13', 'original_unattributed', 'Real change keeps the pace of a season, not a sprint.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'endurance & the long walk', '{}'::text[], 'long arc', NULL),
  ('AN-14', 'original_unattributed', 'You can begin again as many times as you need to.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'returning & beginning again', '{}'::text[], 'rekindle', NULL),
  ('AN-15', 'original_unattributed', 'The company you keep on the hard days is the whole point.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'friendship & carrying each other', '{}'::text[], 'circle', NULL),
  ('AN-16', 'original_unattributed', 'What you do a little of, often, becomes who you are.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'craft & practice', '{}'::text[], 'long arc', NULL),
  ('AN-17', 'original_unattributed', 'The small thing you do today is a gift to who you''ll be.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'craft & practice', '{}'::text[], 'any', NULL),
  ('AN-18', 'original_unattributed', 'Progress is quiet. Trust it even when you can''t hear it.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'endurance & the long walk', '{}'::text[], 'long arc', NULL),
  ('AN-19', 'original_unattributed', 'Kindness toward yourself isn''t the reward for the work. It''s part of it.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'rest & gentleness', '{}'::text[], 'hard day', NULL),
  ('AN-20', 'original_unattributed', 'You don''t have to carry it alone. That''s what the others are for.', NULL, 'Original Rally line — no rights or attribution question by construction.', 'friendship & carrying each other', '{}'::text[], 'circle', NULL);
